import requests,pandas as pd
from functools import wraps
from typing import Dict,Any,Callable
from vnstock_news.utils.logger import setup_logger
from vnstock_news.config.sites import SITES_CONFIG
from urllib.parse import urlparse
logger=setup_logger('vnstock_news.utils.helpers')
def retry_request(max_retries=3):
	A=max_retries
	def B(func):
		@wraps(func)
		def B(*C,**D):
			for B in range(A):
				try:return func(*C,**D)
				except Exception as E:
					logger.warning(f"Attempt {B+1} failed: {E}")
					if B==A-1:raise
			raise Exception('Max retries reached.')
		return B
	return B
@retry_request()
def fetch_url_content(url:str,headers:Dict=None,timeout:int=10)->bytes:A=requests.get(url,headers=headers,timeout=timeout);A.raise_for_status();logger.info(f"Successfully fetched content from {url}");return A.content
def standardize_columns(df:pd.DataFrame,mapping:Dict[str,Any])->pd.DataFrame:A={A:B for(B,C)in mapping.items()for A in C if A in df.columns};return df.rename(columns=A)
def list_supported_sites(display=True):
	D='domain';C='name';A=[]
	def E(config):
		G='base_url';F='current_url';E='urls';D='rss';C='sitemap_url';B='sitemap';A=config
		if A.get(C):return urlparse(A[C]).netloc
		if A.get(D,{}).get(E):return urlparse(A[D][E][0]).netloc
		if A.get(B,{}).get(F):return urlparse(A[B][F]).netloc
		if A.get(B,{}).get(G):return urlparse(A[B][G]).netloc
		return'Không xác định'
	for(F,G)in SITES_CONFIG.items():H=E(G);A.append({C:F,D:H})
	if display:
		print('DANH SÁCH CÁC TRANG WEB ĐƯỢC HỖ TRỢ:');print('='*50);print(f"{'Tên viết tắt':<15} | {'Tên miền'}");print('-'*50)
		for B in A:print(f"{B[C]:<15} | {B[D]}")
		print('='*50)
	return A